spec:
/**
 * Category Management Screen Components
 * 
 * CategoriesScreen: src/screens/CategoriesScreen.tsx
 * - Main screen for managing user-defined categories
 * - Full CRUD functionality with hooks: useCategories, useCreateCategory, useUpdateCategory, useDeleteCategory
 * - Entry counts per category with useEntryCounts hook
 * - Active timer detection with useActiveTimerCategory hook
 * - Pull-to-refresh support
 * 
 * CategoryList: src/components/categories/CategoryList.tsx
 * - Displays categories as cards with color swatch, name, type badge, entry count
 * - Empty state with "Create Your First Category" button
 * - Loading state with Spinner
 * 
 * CategoryForm: src/components/categories/CategoryForm.tsx
 * - Modal form for create/edit with name, type (REQUIRED), and color fields
 * - Type suggestions: work, personal, hobby, study, exercise, project, meeting
 * - Validates with CreateCategorySchema/UpdateCategorySchema from @/schemas
 * - Delete functionality with reassignment options for entries
 * - Active timer detection prevents deletion until timer is stopped
 * 
 * Navigation: wired to Categories tab in MainTabs.tsx with headerShown: false
 */

interface CategoryFormProps {
  visible: boolean;
  onClose: () => void;
  category: Category | null;
  entryCount?: number;
  isSaving?: boolean;
  isDeleting?: boolean;
  onSubmit: (data: CreateCategoryInput | UpdateCategoryInput) => void;
  onDelete?: (categoryId: string) => void;
  onReassignEntries?: (fromCategoryId: string, toCategoryId: string) => void;
  otherCategories?: Category[];
  hasActiveTimer?: boolean;
  onStopTimer?: () => void;
}

interface CategoryListProps {
  categories: Category[];
  entryCounts?: Record<string, number>;
  isLoading?: boolean;
  onCategoryPress: (category: Category) => void;
  onCreatePress: () => void;
  onRefresh?: () => void;
  refreshing?: boolean;
}
